insert into public.event_quizzes (event_id, slug, num, phase, title, sub, hero_img, difficulty, questions, status, sort, published)
values (
  'vm-2026', 'gruppespill-2-komplett', '12', 'Gruppespill omgang 2',
  'Omgang 2 komplett — de siste svarene', 'Norge feller Senegal, Messi-rekord og Ronaldo-historie — kampene 21.–23. juni.', 'vm-gruppespill-1', 'middels',
  '[{"category": "Norge", "q": "Norge slo Senegal 22. juni og sikret avansement fra gruppe I. Hva ble resultatet?", "options": ["1–1", "3–2", "2–1", "4–1"], "correct": 1, "explanation": "Norge vant 3–2 på Gillette Stadium i Foxborough og gikk videre fra gruppe I sammen med Frankrike."}, {"category": "Haaland", "q": "Erling Haaland scoret to mål mot Senegal (48. og 58. minutt). Hvor mange VM-mål hadde han dermed totalt i mesterskapet?", "options": ["To", "Tre", "Fem", "Fire"], "correct": 3, "explanation": "Etter dobbelen mot Senegal var Haaland oppe i fire mål i VM 2026 — han scoret også to mot Irak i åpningskampen."}, {"category": "Messi-rekord", "q": "Argentina slo Østerrike 2–0 den 22. juni. Hvilken milepæl nådde Lionel Messi med sine to mål?", "options": ["Han scoret sitt aller første VM-mål", "Han ble VM-sluttspillenes mestscorende gjennom tidene", "Han ble matchens yngste målscorer", "Han tangerte Kloses rekord for aller første gang"], "correct": 1, "explanation": "Messi passerte Miroslav Kloses 16 mål og ble alenehersker på VM-toppscorerlista med 18 mål; han hadde tangert rekorden med hat-trick mot Algerie i åpningskampen."}, {"category": "Frankrike", "q": "Frankrike slo Irak 3–0 den 22. juni i en kamp som ble avbrutt av noe uvanlig. Hva?", "options": ["Streik blant kampfunksjonærene", "Et to timer langt væropphold på grunn av lyn og uvær", "En bane-invasjon fra tilskuere", "Strømbrudd på hele stadion"], "correct": 1, "explanation": "Kampen i Philadelphia-området fikk VM 2026s aller første værforsinkelse — rundt to timer på grunn av lynfare. Kylian Mbappé scoret to og Ousmane Dembélé ett."}, {"category": "Egypt", "q": "Egypt tok sin aller første VM-seier noensinne i sin andre gruppekamp, 3–1 over New Zealand. Hvilken stjernespiss scoret?", "options": ["Mostafa Mohamed", "Omar Marmoush", "Trezeguet", "Mohamed Salah"], "correct": 3, "explanation": "Mohamed Salah scoret da Egypt snudde til 3–1-seier i Vancouver — landets første seier i et VM-sluttspill etter deltakelser i 1934, 1990 og 2018."}, {"category": "Spania", "q": "Spania svarte på den skuffende åpningen (0–0 mot Kapp Verde) med en real opptur 21. juni. Hva ble resultatet mot Saudi-Arabia?", "options": ["1–0 til Spania", "2–2", "0–1 til Saudi-Arabia", "4–0 til Spania"], "correct": 3, "explanation": "Spania vant 4–0 i Atlanta; Lamine Yamal og Mikel Oyarzabal (to mål) var blant scorerne."}, {"category": "Japan", "q": "Japan vant 4–0 den 21. juni og sendte motstanderen ut av VM. Hvilket land røk dermed ut?", "options": ["Marokko", "Tunisia", "Algerie", "Egypt"], "correct": 1, "explanation": "Japan knuste Tunisia 4–0, med blant annet to mål av Ayase Ueda; Tunisia var dermed slått ut av mesterskapet."}, {"category": "Portugal", "q": "Portugal vant 5–0 over Usbekistan 23. juni. Hvilken historisk rekord satte Cristiano Ronaldo med sin dobbel?", "options": ["Flest VM-kamper som kaptein", "Første som scorer hat-trick i tre strake VM", "Eldste målscorer i VM-historien", "Første spiller som scorer i seks ulike VM-sluttspill"], "correct": 3, "explanation": "Ronaldos to mål gjorde ham til den aller første spilleren som har scoret i seks forskjellige VM-sluttspill."}, {"category": "England", "q": "England fortsatte ubeseiret, men skuffet med målløst uavgjort 23. juni. Mot hvilket lag?", "options": ["Kroatia", "Ghana", "Senegal", "Panama"], "correct": 1, "explanation": "England og Ghana spilte 0–0; England dominerte, men traff blant annet tverrliggeren uten å få ballen i mål."}, {"category": "Kroatia", "q": "Kroatia vant 1–0 over Panama 23. juni. Hva betydde resultatet for Panama?", "options": ["Panama gikk videre til sluttspillet", "Panama var slått ut — fortsatt uten et eneste VM-poeng i to mesterskap", "Panama sikret gruppeseier", "Panama tvang fram et omspill"], "correct": 1, "explanation": "Ante Budimir avgjorde i det 54. minutt; Panama var ute og venter fortsatt på sitt aller første VM-poeng."}]'::jsonb, 'locked', 12, true
)
on conflict (event_id, slug) do update set
  num=excluded.num, phase=excluded.phase, title=excluded.title, sub=excluded.sub,
  hero_img=excluded.hero_img, difficulty=excluded.difficulty, questions=excluded.questions,
  status=excluded.status, sort=excluded.sort, published=excluded.published;

